504→async function commandQueue(jsonOutput: boolean): Promise<void> {
505→  const scanResults = readLatestScanResults();
506→  const queue = scanResults.filter((r) => r.tier === "apply" && r.filter_status === "pass");
507→
508→  let profile: MasterProfile;
509→  try {
510→    profile = await loadMasterProfile();
511→  } catch (err) {
512→    console.error(`FATAL: Cannot load master-profile.yaml: ${err instanceof Error ? err.message : err}`);
513→    process.exit(1);
514→  }
515→
516→  const filtered = filterApplyQueue(queue, profile);
517→
518→  const applications = readApplications();
519→  const appliedHashes = new Set(applications.map((a) => a.dedup_hash));
520→
521→  // Remove already-applied jobs from queue
522→  const pending = filtered.filter((r) => !appliedHashes.has(r.dedup_hash));
523→
524→  if (jsonOutput) {
525→    console.log(JSON.stringify({ queue_size: pending.length, jobs: pending }));
526→    return;
527→  }
528→
529→  console.log(`Auto-apply queue: ${pending.length} jobs`);
530→  for (const job of pending.slice(0, 20)) {
531→    console.log(`  ${job.match_score}% | ${job.title} @ ${job.company} (${job.source})`);
532→  }
533→}
