145→// ─── Cookie Persistence ───────────────────────────────────────────────────────
146→
147→interface SavedCookie {
148→  name: string;
149→  value: string;
150→  domain: string;
151→  path: string;
152→  expires: number;
153→  httpOnly: boolean;
154→  secure: boolean;
155→  sameSite: "Strict" | "Lax" | "None";
156→}
157→
158→function getCookiePath(site: string): string {
159→  return join(COOKIE_DIR, `${site}.json`);
160→}
161→
162→/**
163→ * Save browser context cookies to disk for a given site.
164→ * Uses Playwright's context.cookies() for full cookie access (including httpOnly).
165→ */
166→export async function saveSiteCookies(
167→  page: import("playwright").Page,
168→  site: string
169→): Promise<number> {
170→  if (!existsSync(COOKIE_DIR)) mkdirSync(COOKIE_DIR, { recursive: true });
171→  const cookies = await page.context().cookies();
172→  writeFileSync(getCookiePath(site), JSON.stringify(cookies, null, 2));
173→  return cookies.length;
174→}
175→
176→/**
177→ * Load saved cookies into a browser context before navigation.
178→ * Returns the number of cookies loaded, or 0 if no saved state.
179→ */
180→export async function loadSiteCookies(
181→  page: import("playwright").Page,
182→  site: string
183→): Promise<number> {
184→  const cookiePath = getCookiePath(site);
185→  if (!existsSync(cookiePath)) return 0;
186→  try {
187→    const raw = readFileSync(cookiePath, "utf-8");
188→    const cookies = JSON.parse(raw) as SavedCookie[];
189→    // Filter out expired cookies
190→    const now = Date.now() / 1000;
191→    const valid = cookies.filter((c) => c.expires === -1 || c.expires === 0 || c.expires > now);
192→    if (valid.length === 0) return 0;
193→    await page.context().addCookies(valid);
194→    return valid.length;
195→  } catch {
196→    return 0;
197→  }
198→}
